import java.util.Scanner;
import java.util.Arrays;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Fix: Limit user input to the size of the buffer
        byte[] buffer = new byte[10];

        if (userInput.length() > buffer.length) {
            System.out.println("Input exceeds buffer size. Please enter a shorter string.");
            return;
        }

        // Copy user input to buffer with proper bounds checking
        byte[] userInputBytes = userInput.getBytes();

        // Use Math.min to ensure we don't copy more bytes than available in either array
        System.arraycopy(userInputBytes, 0, buffer, 0, Math.min(userInputBytes.length, buffer.length));

        System.out.println("Buffer content: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
